#include <bits/stdc++.h>
using namespace std;

// Global variables
const int MAXN = 10001;
vector<int> adj[MAXN]; // Adjacency list for graph representation
int visited[MAXN];     // Array to keep track of visited nodes
int in[MAXN];         // Discovery time for each node
int low[MAXN];        // Low values for each node
int timer;            // Timer to assign discovery times
set<int> bridges;     // Set to store bridge edges

// DFS function to explore the graph and find bridges
void dfs(int node, int parent) {
    visited[node] = 1;  // Mark the current node as visited
    in[node] = low[node] = timer++; // Set discovery time and low value for the current node

    // Traverse through all adjacent nodes
    for (int neighbor : adj[node]) {
        if (neighbor == parent) continue; // Skip the parent node to prevent going back

        if (visited[neighbor] == 1) {
            // If the adjacent node is already visited, update the low value
            low[node] = min(low[node], in[neighbor]);
        } else {
            // Recursively perform DFS on the unvisited adjacent node
            dfs(neighbor, node);

            // Check if the current edge is a bridge
            if (low[neighbor] > in[node]) {
                // If it's a bridge, add both nodes to the set
                bridges.insert(node);
                bridges.insert(neighbor);
            }

            // Update the low value of the current node
            low[node] = min(low[node], low[neighbor]);
        }
    }
}

int main() {
    // Input: number of edges and vertices
    int edge, vertex;
    cin >> edge >> vertex;

    // Initialize adjacency list
    for (int i = 0; i <= vertex; i++) {
        adj[i].clear(); // Clear previous values (if any)
    }

    // Read the edges and build the adjacency list
    for (int i = 0; i < edge; i++) {
        int a, b;
        cin >> a >> b;
        adj[a].push_back(b); // Add edge from a to b
        adj[b].push_back(a); // Add edge from b to a (undirected graph)
    }

    // Start DFS from node 0 with no parent (-1)
    timer = 0; // Start timer at 0
    dfs(0, -1);

    // If no bridge edges are found, output -1
    if (bridges.empty()) {
        cout << -1 << endl;
    } else {
        // Output all the bridge edges found in the graph
        for (int i : bridges) {
            cout << i << endl;
        }
    }

    return 0;
}

