// Function to find critical planets (bridges)
function findCriticalPlanets(n, edges) {
    // Create an adjacency list with n + 1 empty arrays
    let adj = Array.from({ length: n + 1 }, () => []);

    // Build adjacency list from edges
    for (let [u, v] of edges) {
        adj[u].push(v); // Add edge from u to v
        adj[v].push(u); // Add edge from v to u (undirected graph)
    }

    // Arrays to keep track of visited nodes, discovery times, and low values
    let visited = new Array(n + 1).fill(0);
    let inTime = new Array(n + 1).fill(0);
    let low = new Array(n + 1).fill(0);
    let bridges = new Set(); // Set to store the critical planets (bridges)
    let timer = 0; // Timer for discovery times

    // Depth-First Search (DFS) function to find bridges
    function dfs(node, parent) {
        visited[node] = 1;
        inTime[node] = low[node] = timer;
        timer++; // Increment the timer for the next node

        for (let neighbor of adj[node]) {
            if (neighbor === parent) continue; // Skip the parent node

            if (visited[neighbor] === 1) {
                // Update the low value of the current node
                low[node] = Math.min(low[node], inTime[neighbor]);
            } else {
                dfs(neighbor, node); // Recursively perform DFS on the unvisited neighbor

                // Check if the current edge is a bridge
                if (low[neighbor] > inTime[node]) {
                    bridges.add(node);
                    bridges.add(neighbor);
                }

                // Update the low value of the current node
                low[node] = Math.min(low[node], low[neighbor]);
            }
        }
    }

    // Start DFS from node 1 (assuming nodes are 1-indexed)
    for (let i = 1; i <= n; i++) {
        if (visited[i] === 0) {
            dfs(i, -1); // Start DFS with no parent
        }
    }

    // Check if there are critical planets (bridges)
    if (bridges.size === 0) {
        return [-1]; // No critical planets
    }

    // Convert the Set to an array and sort it before returning
    return Array.from(bridges).sort((a, b) => a - b);
}

// Main function to handle input and invoke the critical planets finder
function main() {
    // Read input from stdin, split by lines, and trim
    const input = require('fs').readFileSync(0, 'utf-8').trim().split('\n');

    // Extract number of edges (m) and nodes (n) from the first line
    const [m, n] = input[0].split(' ').map(Number);

    // Initialize edges array
    const edges = [];

    // Read edges from subsequent lines
    for (let i = 1; i <= m; i++) {
        const [u, v] = input[i].split(' ').map(Number);
        edges.push([u, v]); // Add edge to edges array
    }

    // Find critical planets and print the result
    const result = findCriticalPlanets(n, edges);
    console.log(result.join(' ')); // Print the result in a single line
}

// Execute the main function
main();
